// compile-filters reads the v3 list-endpoint filter specs declared in
// internal/storage/filters and emits openapi/v3/v3-filters.generated.yaml. The
// generated file is merged into openapi.yaml by openapi-merge-cli (see
// openapi/openapi-merge.json) so that the SDK and the frontend can introspect
// the filterable properties of each list endpoint.
package main

import (
	"flag"
	"fmt"
	"log"
	"os"
	"strings"

	"github.com/formancehq/payments/internal/storage/filters"
)

func main() {
	output := flag.String("output", "openapi/v3/v3-filters.generated.yaml",
		"Path of the YAML file to write")
	flag.Parse()

	var b strings.Builder
	b.WriteString("# AUTO-GENERATED by tools/compile-filters; DO NOT EDIT.\n")
	b.WriteString("# Source: internal/storage/filters/*.go\n")
	b.WriteString("components:\n")
	b.WriteString("  schemas:\n")

	for _, spec := range filters.All() {
		if spec.Internal {
			continue
		}
		writeFilter(&b, spec)
		writeQueryBuilder(&b, spec)
	}

	if err := os.WriteFile(*output, []byte(b.String()), 0o644); err != nil {
		log.Fatalf("write %s: %v", *output, err)
	}
}

func writeFilter(b *strings.Builder, spec filters.Spec) {
	name := "V3" + spec.Resource + "Filter"
	desc := fmt.Sprintf("Filterable properties for %s.", spec.EndpointPath)

	fmt.Fprintf(b, "    %s:\n", name)
	b.WriteString("      type: object\n")
	writeDescription(b, "      ", desc)
	b.WriteString("      properties:\n")
	for _, f := range spec.Fields {
		writeField(b, f)
	}
}

func writeQueryBuilder(b *strings.Builder, spec filters.Spec) {
	name := "V3" + spec.Resource + "QueryBuilder"
	filterName := "V3" + spec.Resource + "Filter"
	desc := fmt.Sprintf("Query body for %s. Filterable keys are listed on %s.", spec.EndpointPath, filterName)

	fmt.Fprintf(b, "    %s:\n", name)
	b.WriteString("      type: object\n")
	b.WriteString("      additionalProperties: true\n")
	writeDescription(b, "      ", desc)
	b.WriteString("      properties:\n")
	b.WriteString("        $match:\n")
	fmt.Fprintf(b, "          $ref: '#/components/schemas/%s'\n", filterName)
}

func writeField(b *strings.Builder, f filters.Field) {
	fmt.Fprintf(b, "        %s:\n", f.Name)
	switch f.Type {
	case filters.TypeString:
		b.WriteString("          type: string\n")
	case filters.TypeBigInt:
		b.WriteString("          type: integer\n")
		b.WriteString("          format: bigint\n")
	case filters.TypeRef:
		fmt.Fprintf(b, "          $ref: '#/components/schemas/%s'\n", f.OpenAPIRef)
	default:
		log.Fatalf("filters: field %q has unsupported type %d", f.Name, f.Type)
	}
	if f.Description != "" {
		writeDescription(b, "          ", f.Description)
	}
}

// writeDescription writes a YAML "description: ..." entry, using a folded block
// scalar when the text is long enough that a single line would harm readability.
func writeDescription(b *strings.Builder, indent, desc string) {
	if desc == "" {
		return
	}
	if !strings.ContainsAny(desc, "\n") && len(desc) < 120 {
		fmt.Fprintf(b, "%sdescription: %s\n", indent, yamlSingleQuote(desc))
		return
	}
	// Folded scalar — preserves line breaks-as-spaces for long descriptions.
	fmt.Fprintf(b, "%sdescription: >-\n", indent)
	for line := range strings.SplitSeq(desc, "\n") {
		fmt.Fprintf(b, "%s  %s\n", indent, line)
	}
}

// yamlSingleQuote wraps the value in single quotes if it contains any character
// that could confuse a YAML parser ($, :, #, etc.). Single-quoted YAML strings
// only need '' to escape an internal single quote.
func yamlSingleQuote(s string) string {
	if !strings.ContainsAny(s, ":#&*!|>'\"%@`$") {
		return s
	}
	return "'" + strings.ReplaceAll(s, "'", "''") + "'"
}
